"""The pluggable pieces: allocation, pricing, payment, and the display board.

Each is an interface (ABC) plus a concrete default. These are the seams that
let the business change behaviour without touching ParkingLot.
"""
from __future__ import annotations

from abc import ABC, abstractmethod
from datetime import datetime
from enum import Enum
from math import ceil
from typing import Optional

from models import (
    ParkingFloor,
    ParkingSpot,
    SpotRequirement,
    SpotSize,
    Ticket,
    VehicleType,
)


# ── Allocation Strategy (the extensibility seam) ─────────────────────────────
# ── WHY THIS CLASS ──────────────────────────────────────────────────────────
# The lot must not hardcode HOW a spot is chosen. This interface lets us swap
# "first available" for "best fit" or "cheapest floor" with zero core changes.
# 🎙️ "Strategy pattern: the lot asks this for spots, it doesn't know the policy."
class SpotAllocationStrategy(ABC):
    @abstractmethod
    def find_spots(
        self, floors: list[ParkingFloor], req: SpotRequirement
    ) -> Optional[list[ParkingSpot]]:
        ...


class FirstAvailableStrategy(SpotAllocationStrategy):
    """First row containing `count` CONTIGUOUS free spots of a fitting size."""

    def find_spots(self, floors, req):
        for floor in floors:
            for spots in floor.rows.values():  # each row is ordered by position
                run: list[ParkingSpot] = []
                for spot in spots:
                    if spot.is_available() and spot.can_fit(req):
                        run.append(spot)
                        # WHY: as soon as the run is long enough, we're done.
                        if len(run) == req.count:
                            return run
                    else:
                        # WHY: a taken/too-small spot BREAKS adjacency. Reset the
                        #      run — this single line is what enforces "contiguous"
                        #      for buses, not just "any 3 large spots".
                        run = []
        return None  # WHY: None = lot full for this requirement -> caller rejects.


# ── Pricing Strategy ─────────────────────────────────────────────────────────
class PricingStrategy(ABC):
    @abstractmethod
    def calculate_fee(self, ticket: Ticket, exit_time: datetime) -> int:
        ...


class HourlyPricingStrategy(PricingStrategy):
    def __init__(self, rates: Optional[dict[VehicleType, int]] = None) -> None:
        self.rates = rates or {
            VehicleType.MOTORCYCLE: 10,
            VehicleType.CAR: 20,
            VehicleType.BUS: 50,
        }

    def calculate_fee(self, ticket, exit_time):
        seconds = (exit_time - ticket.entry_time).total_seconds()
        # WHY: integer money + ceil to whole hours + min 1 hour. 5 minutes still
        #      bills one hour, and there's no floating-point drift on the total.
        if seconds < 0:
            seconds = 0
        hours = max(1, ceil(seconds / 3600))
        return hours * self.rates[ticket.vehicle.vtype]


# ── Payment Gateway (external dependency behind an interface) ─────────────────
class PaymentResult(Enum):
    SUCCESS = "success"
    FAILURE = "failure"


class PaymentGateway(ABC):
    @abstractmethod
    def charge(self, amount: int) -> PaymentResult:
        ...


class AlwaysSuccessGateway(PaymentGateway):
    def charge(self, amount):
        return PaymentResult.SUCCESS


class ScriptedFakeGateway(PaymentGateway):
    """Returns results from a list in order; last result repeats.

    Lets me test 'fail first, succeed on retry' deterministically.
    """

    def __init__(self, results: list[PaymentResult]) -> None:
        self._results = list(results)

    def charge(self, amount):
        if len(self._results) > 1:
            return self._results.pop(0)
        return self._results[0]


# ── DisplayBoard: the Observer ───────────────────────────────────────────────
# ── WHY THIS CLASS ──────────────────────────────────────────────────────────
# Boards must show live free counts without the lot knowing board internals.
# The lot just shouts "spot X taken/freed"; the board updates its own counters.
# 🎙️ "Observer: the lot notifies, the board listens. Adding a mobile counter
#      later is just one more listener — no core change."
class SpotObserver(ABC):
    @abstractmethod
    def on_change(self, spot: ParkingSpot, occupied: bool) -> None:
        ...


class DisplayBoard(SpotObserver):
    def __init__(self, floors: list[ParkingFloor]) -> None:
        self.free: dict[SpotSize, int] = {s: 0 for s in SpotSize}
        for floor in floors:
            for spot in floor.all_spots():
                if spot.is_available():
                    self.free[spot.size] += 1

    def on_change(self, spot, occupied):
        # WHY: O(1) incremental update on each event — never rescan the lot.
        self.free[spot.size] += -1 if occupied else 1

    def snapshot(self) -> dict[SpotSize, int]:
        return dict(self.free)

